{"code": "# Load and analyze bladder cancer clinical data and CDH1 mutations
import json
import pandas as pd
import os

# Get the file path from storage (if available)
# Based on the pattern, the file should be in /tmp/
tmp_files = [f for f in os.listdir('/tmp') if f.endswith('.json')]
bladder_file = None
cdh1_file = None

for f in tmp_files:
    # The bladder cancer data should be the large file from query 52
    # The CDH1 mutations should be from query 36
    if '52' in f or 'bladder' in f.lower():
        bladder_file = f'/tmp/{f}'
    if '36' in f or 'cdh1' in f.lower():
        cdh1_file = f'/tmp/{f}'

# Try different naming patterns
if not bladder_file:
    for f in tmp_files:
        if 'clinical' in f.lower():
            bladder_file = f'/tmp/{f}'
            break

if not cdh1_file:
    for f in tmp_files:
        if 'mutation' in f.lower() or 'cdh1' in f.lower():
            cdh1_file = f'/tmp/{f}'
            break

# If still not found, use raw query results
print('__RESULT__:')
print(json.dumps({
    'tmp_files': tmp_files,
    'bladder_file_found': bladder_file is not None,
    'cdh1_file_found': cdh1_file is not None,
    'bladder_file_path': bladder_file,
    'cdh1_file_path': cdh1_file
}))"}

