import json

# Load bladder clinical data from storage
bladder_result = locals()['var_functions.query_db:66']
if isinstance(bladder_result, str):
    with open(bladder_result, 'r') as f:
        bladder_clinical = json.load(f)
else:
    bladder_clinical = bladder_result

# Load CDH1 mutation data from storage
cdh1_result = locals()['var_functions.query_db:36']
if isinstance(cdh1_result, str):
    with open(cdh1_result, 'r') as f:
        cdh1_mutations = json.load(f)
else:
    cdh1_mutations = cdh1_result

# Extract patient barcodes with CDH1 mutations
cdh1_patient_barcodes = set()
for mutation in cdh1_mutations:
    if 'ParticipantBarcode' in mutation:
        barcode = mutation['ParticipantBarcode']
        # Extract patient ID from TCGA barcode (format: TCGA-XX-YYYY)
        parts = barcode.split('-')
        if len(parts) >= 3:
            patient_id = parts[2]
            cdh1_patient_barcodes.add(patient_id)

# Process bladder cancer patients and calculate CDH1 mutation rates by histology
histology_stats = {}

for patient in bladder_clinical:
    patient_id = patient.get('patient_id')
    hist_type = patient.get('histological_type')

    if not hist_type or hist_type == "None":
        hist_type = "Unspecified"

    if hist_type not in histology_stats:
        histology_stats[hist_type] = {'total': 0, 'with_cdh1': 0}

